import java.util.*;

public class Main {
    public static void main(String[] args) {
        String input = "i love programming love"; // static input

        // Use LinkedHashMap to maintain order
        Map<Character, Integer> freqMap = new LinkedHashMap<>();

        for (char c : input.toCharArray()) {
            if (c != ' ') { // ignore spaces
                freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);
            }
        }

        // Print result
        for (Map.Entry<Character, Integer> entry : freqMap.entrySet()) {
            System.out.print(entry.getKey() + "=" + entry.getValue() + ", ");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        String input = "Hello World";

        StringBuilder sb = new StringBuilder(input);

        // Find space index (separator between words)
        int spaceIndex = sb.indexOf(" ");

        // Extract two words
        String firstWord = sb.substring(0, spaceIndex);
        String secondWord = sb.substring(spaceIndex + 1);

        // Clear StringBuilder
        sb.setLength(0);

        // Append in swapped order
        sb.append(secondWord).append(" ").append(firstWord);

        // Print result
        System.out.println(sb.toString());
    }
}
